html:
{%- macro add_header(page_num, max_pages, doc, letter_head, no_letterhead) -%}
{% if letter_head and not no_letterhead %}
<div style="height:22.5mm;" class="letter-head">
  {{ letter_head }}
</div>
{% endif %}
{%- endmacro -%}

<div id="header-html" class="hidden-pdf">
  {{ add_header(0,1,doc,letter_head, no_letterhead) }}
</div>

<style>

@page {
    size: A4;
    margin: 12mm;
}

body {
    font-family: Arial, sans-serif;
    font-size: 11px;
}

table {
    width: 100%;
    border-collapse: collapse;
    font-size: 10px;
}

table, th, td {
    border: 1px solid #aaa;
}

th, td {
    padding: 6px;
}

.no-border td, .no-border th {
    border: none !important;
}

table{
page-break-inside:auto;
}

tr{
page-break-inside:avoid;
}

</style>


<!-- TITLE -->
<div style="text-align:center; margin-bottom:2px;">
<h4 style="margin:0;"><strong>Quality Inspection Report</strong></h4>
</div>


<table class="no-border" style="margin-bottom:3px; font-size:11px; width:100%;">
<tr>

<td style="width:20%; padding:3px 2px;">VENDOR NAME</td>
<td style="width:2%; text-align:center;">:</td>
<td style="width:33%; padding-left:3px;">
{{ frappe.db.get_value("Supplier", doc.supplier, "supplier_name") }}
</td>

<td style="width:13%; padding:3px 2px; text-align:right;">DATE</td>
<td style="width:2%; text-align:center;">:</td>
<td style="width:30%; padding-left:3px;">
{{ doc.posting_date }}
</td>

</tr>


<tr>

<td style="padding:3px 2px;">
{% if doc.type == "Purchase Order Based" %}
PO NO.
{% elif doc.type == "GRN Based" %}
GRN NO.
{% endif %}
</td>

<td style="text-align:center;">:</td>

<td style="padding-left:3px;">
{% if doc.type == "Purchase Order Based" %}
{{ doc.po_no }}
{% elif doc.type == "GRN Based" %}
{{ doc.grn_name }}
{% endif %}
</td>

<td style="text-align:right; padding:3px 2px;">PRJ NO.</td>
<td style="text-align:center;">:</td>
<td style="padding-left:3px;">
{{ doc.project }}
</td>

</tr>


<tr>

<td style="padding:3px 2px;">SUB</td>
<td style="text-align:center;">:</td>
<td style="padding-left:3px;">
MOM between Clevertech and {{ frappe.db.get_value("Supplier", doc.supplier, "supplier_name") }}
</td>

<td></td>
<td></td>
<td></td>

</tr>
</table>


<!-- ITEMS TABLE -->

<table>

<thead>

<tr>

<th style="width:7%; text-align:center;">Sr No.</th>
<th style="width:19%; text-align:center;">Part Code</th>
<th style="width:25%; text-align:center;">Item Description</th>
<th style="width:4%; text-align:center;">Qty</th>
<th style="width:12%; text-align:center;">Accepted Qty</th>
<th style="width:11%; text-align:center;">Rejected Qty</th>
<th style="width:13%; text-align:center;">Type of Issue</th>
<th style="width:11%; text-align:center;">Reason</th>

</tr>

</thead>

<tbody>

{% for row in doc.grn_items_quality_reqd %}

<tr>

<td>{{ loop.index }}</td>
<td style="text-align:center;">{{ row.item_code }}</td>
<td style="text-align:center;">{{ row.item_name }}</td>
<td style="text-align:center;">{{ row.po_qty }}</td>
<td style="text-align:center;">{{ row.accepted_qty }}</td>
<td style="text-align:center;">{{ row.rejected_qty }}</td>
<td style="text-align:center;">{{ row.type_of_issue }}</td>
<td style="text-align:center;">{{ row.reason or "" }}</td>

</tr>

{% endfor %}

</tbody>

</table>


<!-- NOTES -->

{% if doc.notes %}

<div style="margin-top:12px; page-break-inside:avoid;">

<strong>NOTES:</strong>

<div style="margin-top:6px;">
{{ doc.notes }}
</div>

</div>

{% else %}

<div style="margin-top:12px;">
<strong>NOTES:</strong>
</div>

{% endif %}


<!-- spacer for bottom footer -->

<div style="height:760px;"></div>


<!-- FOOTER -->
<div style="position:fixed; bottom:35mm; left:0; right:0; page-break-inside:avoid;">
<!--<div style="page-break-inside:avoid;"> -->

{% if not no_letterhead and footer %}
{{ footer }}
{% endif %}

<div style="text-align:center;font-size:10px;margin-top:5px;">
Page <span class="page"></span> of <span class="topage"></span>
</div>

</div>
